package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.util.Objects;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testSetObjectToNumberStrategy_WithValidStrategy_ShouldSetFieldAndReturnThis() throws Exception {
    ToNumberStrategy mockStrategy = mock(ToNumberStrategy.class);

    GsonBuilder returned = gsonBuilder.setObjectToNumberStrategy(mockStrategy);

    assertSame(gsonBuilder, returned);

    // Verify that the private field objectToNumberStrategy is set to mockStrategy
    Field field = GsonBuilder.class.getDeclaredField("objectToNumberStrategy");
    field.setAccessible(true);
    Object fieldValue = field.get(gsonBuilder);
    assertSame(mockStrategy, fieldValue);
  }

  @Test
  void testSetObjectToNumberStrategy_WithNull_ShouldThrowNullPointerException() {
    assertThrows(NullPointerException.class, () -> gsonBuilder.setObjectToNumberStrategy(null));
  }
}
